        full_args = [command_type] + args_list
    else:
        full_args = args_list

    # Parse the arguments
    parsed_args = cli.parse_args(full_args)

    # Initialize configuration dictionary
    config = {}

    if command_type == "build":
        # Extract build-specific parameters
        if hasattr(parsed_args, 'docs_path'):
            config['docs_path'] = parsed_args.docs_path
        if hasattr(parsed_args, 'output_dir'):
            config['output_dir'] = parsed_args.output_dir
        if hasattr(parsed_args, 'embedding_model'):
            config['embedding_model'] = parsed_args.embedding_model
        if hasattr(parsed_args, 'chunk_size'):
            config['chunk_size'] = parsed_args.chunk_size
        if hasattr(parsed_args, 'chunk_overlap'):
            config['chunk_overlap'] = parsed_args.chunk_overlap
        if hasattr(parsed_args, 'batch_size'):
            config['batch_size'] = parsed_args.batch_size
        if hasattr(parsed_args, 'max_workers'):
            config['max_workers'] = parsed_args.max_workers

    elif command_type == "search":
        # Extract search-specific parameters
        if hasattr(parsed_args, 'query'):
            config['query'] = parsed_args.query
        if hasattr(parsed_args, 'index_path'):
            config['index_path'] = parsed_args.index_path
        if hasattr(parsed_args, 'top_k'):
            config['top_k'] = parsed_args.top_k
        if hasattr(parsed_args, 'threshold'):
            config['threshold'] = parsed_args.threshold
        if hasattr(parsed_args, 'rerank'):
            config['rerank'] = parsed_args.rerank
        if hasattr(parsed_args, 'embedding_model'):
            config['embedding_model'] = parsed_args.embedding_model

    # Convert Path objects to strings for better serialization
    for key, value in list(config.items()):
        if isinstance(value, Path):
            config[key] = str(value)
        # Remove None values
        elif value is None:
            config.pop(key, None)

    return config
